              <button className="reg-btn" style={{ fontSize: 12, padding: '8px 18px' }} onClick={() => { setBrochureOpen(false); setRegOpen(true); }}>
                Apply Now
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
